={{ (() => {
  // 1. doc_type 영문 → 한국어 매핑
  const docTypeMap = {
    "passport": "여권",
    "academic_certificate": "재학증명",
    "financial_statement": "재정증명",
    "residence_proof": "체류지입증",
    "tb_test": "결핵진단서",
    "application_form": "통합신청서",
    "photo": "표준규격 사진",
    "business_registration": "교육기관 사업자등록증",
    "admission_letter": "표준입학허가서",
    "family_relations": "가족관계 입증서류",
    "professor_confirmation": "지도교수 확인서"
  };

  // 2. VisaRequirement에서 한국어 doc_type → UUID 매핑 만들기
  const visaRequirements = $('DB Select: VisaRequirement').all();
  const docTypeToReqId = {};
  for (const req of visaRequirements) {
    if (req.json && req.json.doc_type) {
      docTypeToReqId[req.json.doc_type] = req.json.requirement_id;
    }
  }

  // 3. 영문 doc_type → UUID 변환 함수
  const getReqIdByDocType = (docTypeEn) => {
    const docTypeKr = docTypeMap[docTypeEn];
    if (!docTypeKr) return null;
    return docTypeToReqId[docTypeKr] || null;
  };

  // 4. rule_results + Solar items 합치기
  const ruleResults = $('Transform: Checklist Validation').item.json.rule_results;
  const solarItems = JSON.parse($('Solar Judgment').item.json.choices[0].message.content).items;

  // 5. Solar items의 req_id를 UUID로 변환
  const solarItemsWithUuid = solarItems.map(item => ({
    ...item,
    req_id: getReqIdByDocType(item.doc_type),
    evidence_doc_id: null
  }));

  // 6. 합쳐서 ChecklistItem 형식으로 변환
  const finalArray = [...ruleResults, ...solarItemsWithUuid].map(item => ({
    session_id: $('Merge: UserSession Result').item.json.session_id,
    visa_type: $('Webhook').item.json.body.visa_type,
    doc_type: item.doc_type,
    req_id: item.req_id || null,
    status: item.status,
    decision_by: item.decision_by,
    reason: item.reason,
    evidence_doc_id: item.evidence_doc_id || null
  }));

  // 7. 빈 배열 처리 — 분석만 한 케이스 (residence_proof, admission_letter 등 룰 없는 서류)
  if (finalArray.length === 0) {
    return [{
      session_id: $('Merge: UserSession Result').item.json.session_id,
      visa_type: $('Webhook').item.json.body.visa_type,
      doc_type: $('Transform: Checklist Validation').item.json.extracted_data.document_type || "other",
      req_id: null,
      status: "completed",
      decision_by: "rule",
      reason: "서류 분석 완료 (별도 검증 규칙 없음)",
      evidence_doc_id: null
    }];
  }

  return finalArray;
})() }}

