// ============================================
// 0. doc_type 라벨 매핑
// ============================================
const docTypeKoMap = {
  "application_form": "체류자격 연장 신청서",
  "passport": "여권 사본",
  "academic_certificate": "재학증명서·성적증명서",
  "financial_statement": "잔고증명서",
  "residence_proof": "체류지 입증서류",
  "tb_test": "결핵진단서",
  "family_relations": "가족관계 입증서류",
  "admission_letter": "표준입학허가서",
  "business_registration": "교육기관 사업자등록증",
  "photo": "표준규격 사진",
  "professor_confirmation": "지도교수 확인서",
  "other": "기타 서류"
};

const docTypeEnMap = {
  "application_form": "Visa Extension Application",
  "passport": "Passport Copy",
  "academic_certificate": "Academic Certificate / Transcript",
  "financial_statement": "Bank Balance Certificate",
  "residence_proof": "Proof of Residence",
  "tb_test": "Tuberculosis Test Result",
  "family_relations": "Family Relations Certificate",
  "admission_letter": "Standard Admission Letter",
  "business_registration": "Educational Institution Registration",
  "photo": "Standard Photo",
  "professor_confirmation": "Professor Confirmation",
  "other": "Other Document"
};

// ============================================
// 1. 누적된 checklist_item 조회 + dedup
// ============================================
const allChecklistItems = $('DB Select: AllChecklistItems').all().map(item => item.json);

const statusPriority = { "missing": 4, "invalid": 3, "warning": 2, "completed": 1 };

const docTypeDedupMap = {};
for (const item of allChecklistItems) {
  const docType = item.doc_type;
  if (!docTypeDedupMap[docType]) {
    docTypeDedupMap[docType] = item;
  } else {
    const existingPriority = statusPriority[docTypeDedupMap[docType].status] || 0;
    const newPriority = statusPriority[item.status] || 0;
    if (newPriority > existingPriority) {
      docTypeDedupMap[docType] = item;
    }
  }
}

const uniqueDocs = Object.values(docTypeDedupMap).filter(it => it.doc_type !== "other");

// ============================================
// 2. documents 배열
// ============================================
// 프론트엔드 매핑 미적용 doc_type만 한국어로 박기 (임시 처리)
const docTypeForFrontend = {
  "academic_certificate": "재학증명서·성적증명서",
  "tb_test": "결핵진단서",
  "family_relations": "가족관계 입증서류"
};

const documents = uniqueDocs.map(it => ({
  doc_type: docTypeForFrontend[it.doc_type] || it.doc_type,
  doc_name: docTypeKoMap[it.doc_type] || it.doc_type,
  status: it.status,
  reason: it.reason
}));

// ============================================
// 2-2. 누락된 필수 서류 자동 추가
// ============================================
const requiredDocTypes = [
  { type: "application_form", reason: "체류자격 연장 신청서가 제출되지 않았어요. 서명한 신청서를 준비해주세요." },
  { type: "passport", reason: "여권 사본이 제출되지 않았어요. 만료일이 180일 이상 남은 여권 사본을 준비해주세요." },
  { type: "academic_certificate", reason: "재학증명서 또는 성적증명서가 제출되지 않았어요. 평점 2.0 이상이면 재정증명 면제도 가능해요." },
  { type: "financial_statement", reason: "재정능력 입증 서류가 제출되지 않았어요. 발급일 30일 이내, 1천만 원 이상 잔고증명서가 필요해요." },
  { type: "residence_proof", reason: "체류지 입증서류가 제출되지 않았어요. 임대차계약서나 기숙사비 영수증을 준비해주세요." }
];

// 업로드된 doc_type 영문 ID 추적 (uniqueDocs 기준)
const uploadedDocTypes = new Set(uniqueDocs.map(d => d.doc_type));

for (const req of requiredDocTypes) {
  if (!uploadedDocTypes.has(req.type)) {
    documents.push({
      doc_type: docTypeForFrontend[req.type] || req.type,  // 한국어 변환 적용
      doc_name: docTypeKoMap[req.type] || req.type,
      status: "missing",
      reason: req.reason
    });
  }
}

// ============================================
// 3. readiness_pct & overall_status
// ============================================
const totalCount = documents.length;
const completedCount = documents.filter(it => it.status === "completed").length;
const readiness_pct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;

let overall_status;
if (documents.length === 0) {
  overall_status = "missing";
} else if (documents.some(it => it.status === "missing")) {
  overall_status = "missing";
} else if (documents.some(it => it.status === "invalid")) {
  overall_status = "invalid";
} else if (documents.some(it => it.status === "warning")) {
  overall_status = "warning";
} else {
  overall_status = "completed";
}

// ============================================
// 5. guidance — Solar 검증 + Fallback
// ============================================

// 5-1. 검증 함수들
const isValidKorean = (g) => {
  if (!g || !g.summary) return false;
  const text = (g.summary || "") + " " + (g.next_action || "");
  const korCount = (text.match(/[가-힣]/g) || []).length;
  const engCount = (text.match(/[a-zA-Z]/g) || []).length;
  return korCount > engCount;
};

const isValidEnglish = (g) => {
  if (!g || !g.summary) return false;
  const text = (g.summary || "") + " " + (g.next_action || "");
  const korCount = (text.match(/[가-힣]/g) || []).length;
  const engCount = (text.match(/[a-zA-Z]/g) || []).length;
  return engCount > korCount;
};

const isConsistentStatus = (g, docStatus) => {
  if (!g) return false;
  const text = (g.summary || "") + " " + (g.next_action || "");

  if (docStatus === "completed") {
    const negativeKeywords = [
      "제출되지 않", "누락", "미제출", "준비해주세요", "발급받아", "다시 제출", 
      "확인되지 않", "입력되지 않", "정보가 없", "정보가 부족",
      "not submitted", "not provided", "missing", "please submit", "please prepare", 
      "please obtain", "not confirmed", "needs to be"
    ];
    return !negativeKeywords.some(kw => text.toLowerCase().includes(kw.toLowerCase()));
  }

  return true;
};

// 5-2. Solar Guidance 결과 파싱
let solarKoMessages = [];
let solarEnMessages = [];

try {
  const guidance_kr = JSON.parse($('Solar Guidance KR').item.json.choices[0].message.content);
  solarKoMessages = guidance_kr.messages || [];
} catch (e) {
  solarKoMessages = [];
}

try {
  const guidance_en = JSON.parse($('Solar Guidance EN').item.json.choices[0].message.content);
  solarEnMessages = guidance_en.messages || [];
} catch (e) {
  solarEnMessages = [];
}

// 5-3. Fallback 안내문 생성기
const getKoFallback = (docType, status, reason) => {
  const docName = docTypeKoMap[docType] || docType;

  if (status === "completed") {
    return {
      doc_type: docType,
      summary: reason || `${docName} 요건을 충족했어요`,
      extracted_value: "",
      required_value: "",
      gap: "",
      next_action: "서류 요건을 충족합니다. 다른 서류 준비에 집중하세요."
    };
  }

  if (status === "missing") {
    const messages = {
      "application_form": "체류자격 연장 신청서에 서명 후 제출해주세요.",
      "passport": "여권 사본을 준비해주세요. 만료일이 180일 이상 남아야 합니다.",
      "academic_certificate": "재학증명서와 성적증명서를 학교에서 발급받으세요. 평점 2.0 이상이면 재정증명 면제 가능합니다.",
      "financial_statement": "본인 또는 부모님 명의의 잔고증명서를 발급일 30일 이내로 준비해주세요. 1,000만원 이상 필요합니다.",
      "residence_proof": "임대차계약서 또는 기숙사비 영수증을 준비해주세요."
    };
    return {
      doc_type: docType,
      summary: reason || `${docName}가 제출되지 않았어요`,
      extracted_value: "",
      required_value: "",
      gap: "",
      next_action: messages[docType] || "해당 서류를 준비해 제출해주세요."
    };
  }

  if (status === "invalid") {
    return {
      doc_type: docType,
      summary: reason || `${docName}가 요건을 충족하지 못해요`,
      extracted_value: "",
      required_value: "",
      gap: "",
      next_action: "서류 조건이 충족되지 않습니다. 재발급 또는 수정 후 다시 제출해주세요."
    };
  }

  return {
    doc_type: docType,
    summary: reason || `${docName} 추가 확인이 필요해요`,
    extracted_value: "",
    required_value: "",
    gap: "",
    next_action: "추가 확인이 필요합니다. 학교 또는 출입국사무소에 문의해보세요."
  };
};

const getEnFallback = (docType, status, reason) => {
  const docName = docTypeEnMap[docType] || docType;

  if (status === "completed") {
    return {
      doc_type: docType,
      summary: `${docName} meets the requirements`,
      extracted_value: "",
      required_value: "",
      gap: "",
      next_action: "This document meets the requirements. Focus on other documents."
    };
  }

  if (status === "missing") {
    const messages = {
      "application_form": "Please sign and submit the visa extension application form.",
      "passport": "Please prepare your passport copy. Validity must be 180+ days.",
      "academic_certificate": "Please obtain academic certificate and transcript from your school. GPA 2.0+ qualifies for financial proof exemption.",
      "financial_statement": "Please prepare a bank balance certificate (issued within 30 days) showing KRW 10,000,000 or more.",
      "residence_proof": "Please prepare a lease contract or dormitory fee receipt."
    };
    return {
      doc_type: docType,
      summary: `${docName} not submitted`,
      extracted_value: "",
      required_value: "",
      gap: "",
      next_action: messages[docType] || "Please submit this document."
    };
  }

  if (status === "invalid") {
    return {
      doc_type: docType,
      summary: `${docName} does not meet requirements`,
      extracted_value: "",
      required_value: "",
      gap: "",
      next_action: "Document does not meet requirements. Please re-issue or correct and resubmit."
    };
  }

  return {
    doc_type: docType,
    summary: `${docName} needs verification`,
    extracted_value: "",
    required_value: "",
    gap: "",
    next_action: "Additional verification needed. Please consult your school or immigration office."
  };
};

// 5-4. documents 기준으로 guidance 매칭 + 검증 + Fallback
const solarKoByDocType = {};
for (const g of solarKoMessages) {
  if (g && g.doc_type) solarKoByDocType[g.doc_type] = g;
}

const solarEnByDocType = {};
for (const g of solarEnMessages) {
  if (g && g.doc_type) solarEnByDocType[g.doc_type] = g;
}

const finalGuidanceKo = documents.map(doc => {
  const solar = solarKoByDocType[doc.doc_type];

  if (solar && isValidKorean(solar) && isConsistentStatus(solar, doc.status)) {
    return solar;
  }

  return getKoFallback(doc.doc_type, doc.status, doc.reason);
});

const finalGuidanceEn = documents.map(doc => {
  const solar = solarEnByDocType[doc.doc_type];

  if (solar && isValidEnglish(solar) && isConsistentStatus(solar, doc.status)) {
    return solar;
  }

  return getEnFallback(doc.doc_type, doc.status, doc.reason);
});

// ============================================
// 6. deadlines
// ============================================
function addDays(dateString, days) {
  if (!dateString || !days) return "";
  const date = new Date(dateString);
  if (isNaN(date.getTime())) return "";
  date.setDate(date.getDate() + days);
  return date.toISOString().slice(0, 10);
}

function getDaysLeft(deadlineDate) {
  if (!deadlineDate) return null;
  const today = new Date();
  const deadline = new Date(deadlineDate);
  today.setHours(0, 0, 0, 0);
  deadline.setHours(0, 0, 0, 0);
  if (isNaN(deadline.getTime())) return null;
  const diff = deadline.getTime() - today.getTime();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
}

function getDeadlineLabel(daysLeft) {
  if (daysLeft === null) return "";
  if (daysLeft < 0) return "만료됨";
  if (daysLeft === 0) return "오늘 마감";
  return `D-${daysLeft}`;
}

function getDeadlineStatus(itemStatus, daysLeft) {
  if (itemStatus === "missing") return "제출 필요";
  if (itemStatus === "invalid") return "재발급 필요";
  if (daysLeft !== null && daysLeft < 0) return "만료됨";
  if (daysLeft !== null && daysLeft <= 7) return "만료임박";
  if (itemStatus === "warning") return "확인 필요";
  if (itemStatus === "completed") return "통과";
  return "확인 필요";
}

const validityDaysByDocType = {
  financial_statement: 30,
  academic_certificate: 30,
  passport: null,
  residence_proof: null,
  tb_test: null,
  family_relations: null,
  admission_letter: null,
  application_form: null,
  photo: null,
  business_registration: null,
  professor_confirmation: null,
  other: null
};

let extracted = {};
try {
  extracted = JSON.parse($('Information Extract').item.json.choices[0].message.content);
} catch (e) {
  extracted = {};
}

const deadlines = documents.map(item => {
  const docType = item.doc_type;
  const issueDate = (extracted.document_type === docType) ? (extracted.issue_date || "") : "";
  const expiryDate = (extracted.document_type === docType) ? (extracted.expiry_date || "") : "";
  const validityDays = validityDaysByDocType[docType] || null;
  const calculatedDeadline = expiryDate || addDays(issueDate, validityDays);
  const daysLeft = getDaysLeft(calculatedDeadline);
  const status = getDeadlineStatus(item.status, daysLeft);
  const label = getDeadlineLabel(daysLeft);

  let task = `${docTypeKoMap[docType] || docType} 확인`;
  let message = item.reason || "";

  return {
    doc_type: docType,
    doc_name: docTypeKoMap[docType] || docType,
    task,
    status,
    base_date: issueDate || expiryDate || "",
    deadline_date: calculatedDeadline || "",
    days_left: daysLeft,
    label,
    message
  };
});

// ============================================
// 7. 최종 응답
// ============================================
return [{
  json: {
    session_id: $('Merge: UserSession Result').item.json.session_id,
    visa_type: $('Webhook').item.json.body.visa_type,
    readiness_pct,
    overall_status,
    deadlines,
    documents,
    guidance: {
      ko: finalGuidanceKo,
      en: finalGuidanceEn
    }
  }
}];

// ============================================
// 1. VisaRequirement에서 doc_type별 UUID 매핑 만들기
// ============================================
const visaRequirements = $('DB Select: VisaRequirement').all();

const docTypeMap = {
  "passport": "여권",
  "academic_certificate": "재학증명",
  "financial_statement": "재정증명",
  "residence_proof": "체류지입증",
  "tb_test": "결핵진단서",
  "application_form": "통합신청서",
  "photo": "표준규격 사진",
  "business_registration": "교육기관 사업자등록증",
  "admission_letter": "표준입학허가서",
  "family_relations": "가족관계 입증서류",
  "professor_confirmation": "지도교수 확인서"
};

const docTypeToReqId = {};
for (const req of visaRequirements) {
  if (req.json && req.json.doc_type) {
    docTypeToReqId[req.json.doc_type] = req.json.requirement_id;
  }
}

function getReqIdByDocType(docTypeEn) {
  const docTypeKr = docTypeMap[docTypeEn];
  if (!docTypeKr) return null;
  return docTypeToReqId[docTypeKr] || null;
}

// ============================================
// 2. Information Extract 결과 파싱
// ============================================
let extracted;
try {
  extracted = JSON.parse($('Information Extract').item.json.choices[0].message.content);
} catch (e) {
  extracted = { document_type: "other" };
}

const ruleResults = [];
const ambiguousItems = [];
const docType = extracted.document_type;

// ============================================
// 3. 룰 기반 판단
// ============================================

// 3-1. document_type 분류 실패 → missing
if (!docType || docType === "other") {
  ruleResults.push({
    req_id: null,
    doc_type: "other",
    status: "missing",
    decision_by: "rule",
    reason: "서류 종류를 식별할 수 없음. 명확한 비자 서류를 업로드해주세요.",
    evidence_doc_id: null
  });
} else {

  // 3-2. financial_statement (재정증명)
  if (docType === "financial_statement") {
    const balance = extracted.balance_amount;
    const currency = extracted.balance_currency;
    const issueDate = extracted.issue_date;
    const reqId = getReqIdByDocType("financial_statement");

    // 외화 환산 처리 (실제 환율 API 사용)
    if (currency && currency !== "KRW") {
      // 환율 API 결과 파싱 (폴백 환율 포함)
      let krwBalance;
      let rateUsed;

      try {
        const ratesData = $('Fetch Exchange Rates').item.json.rates;

        if (currency === "USD") {
          rateUsed = ratesData.KRW;
        } else if (ratesData[currency] && ratesData.KRW) {
          // USD 기준 환율 → 해당 통화 → KRW 변환
          rateUsed = ratesData.KRW / ratesData[currency];
        } else {
          // 통화 데이터 없음 → 폴백
          const fallback = { USD: 1350, CNY: 185, JPY: 8.7, EUR: 1450 };
          rateUsed = fallback[currency] || 1350;
        }
        krwBalance = Math.round(balance * rateUsed);
      } catch (e) {
        // API 실패 → 폴백 환율
        const fallback = { USD: 1350, CNY: 185, JPY: 8.7, EUR: 1450 };
        rateUsed = fallback[currency] || 1350;
        krwBalance = Math.round(balance * rateUsed);
      }

      // 명확히 미달 → invalid
      if (krwBalance <= 9000000) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "financial_statement",
          status: "invalid",
          decision_by: "rule",
          reason: balance + " " + currency + " × " + rateUsed.toFixed(2) + "원 = 약 " + krwBalance.toLocaleString() + "원 (기준 10,000,000원 명확히 미달)",
          evidence_doc_id: null
        });
      }
      else if (krwBalance >= 11000000) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "financial_statement",
          status: "completed",
          decision_by: "rule",
          reason: balance + " " + currency + " × " + rateUsed.toFixed(2) + "원 = 약 " + krwBalance.toLocaleString() + "원 (기준 10,000,000원 명확히 충족)",
          evidence_doc_id: null
        });
      }
      else {
        ruleResults.push({
          req_id: reqId,
          doc_type: "financial_statement",
          status: "warning",
          decision_by: "rule",
          reason: balance + " " + currency + " × " + rateUsed.toFixed(2) + "원 = 약 " + krwBalance.toLocaleString() + "원 (기준 10,000,000원 ±10% 경계선, 환율 변동 주의)",
          evidence_doc_id: null
        });
      }
    }
    // 명확히 미달 → invalid
    else if (balance > 0 && balance <= 9000000) {
      ruleResults.push({
        req_id: reqId,
        doc_type: "financial_statement",
        status: "invalid",
        decision_by: "rule",
        reason: "잔액 " + balance.toLocaleString() + "원은 기준 10,000,000원 명확히 미달 (10% 이상 부족)",
        evidence_doc_id: null
      });
    }
    // 명확히 충족 → completed
    else if (balance >= 11000000) {
      ruleResults.push({
        req_id: reqId,
        doc_type: "financial_statement",
        status: "completed",
        decision_by: "rule",
        reason: "잔액 " + balance.toLocaleString() + "원은 기준 10,000,000원 명확히 충족",
        evidence_doc_id: null
      });
    }
    // ±10% 근접 → warning
    else if (balance > 9000000 && balance < 11000000) {
      ambiguousItems.push({
        doc_type: "financial_statement",
        reason: "잔액 기준 ±10% 근접 (Solar 판단 필요)",
        extracted_value: balance + " KRW"
      });
    }

    // 발급일 체크
    if (issueDate) {
      const daysSinceIssue = Math.floor((new Date() - new Date(issueDate)) / (1000 * 60 * 60 * 24));
      if (daysSinceIssue > 35) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "financial_statement",
          status: "invalid",
          decision_by: "rule",
          reason: "발급일이 " + daysSinceIssue + "일 전으로 30일 명확히 초과 (재발급 필요)",
          evidence_doc_id: null
        });
      } 
      else if (daysSinceIssue >= 0 && daysSinceIssue < 25) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "financial_statement",
          status: "completed",
          decision_by: "rule",
          reason: "발급일 " + daysSinceIssue + "일 전 (30일 이내 명확히 충족)",
          evidence_doc_id: null
        });
      } 
      else if (daysSinceIssue >= 25 && daysSinceIssue <= 35) {
        ambiguousItems.push({
          doc_type: "financial_statement_validity",
          reason: "발급일 30일 경계선 ±5일",
          extracted_value: issueDate
        });
      }
    }
  }

  // 3-3. passport (여권)
  if (docType === "passport") {
    const expiryDate = extracted.expiry_date;
    const reqId = getReqIdByDocType("passport");

    if (expiryDate) {
      const daysToExpiry = Math.floor((new Date(expiryDate) - new Date()) / (1000 * 60 * 60 * 24));

      if (daysToExpiry < 90) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "passport",
          status: "invalid",
          decision_by: "rule",
          reason: "여권 만료까지 " + daysToExpiry + "일 남음 (180일 기준 미달, 갱신 필요)",
          evidence_doc_id: null
        });
      } 
      else if (daysToExpiry > 270) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "passport",
          status: "completed",
          decision_by: "rule",
          reason: "여권 만료까지 " + daysToExpiry + "일 남음 (180일 기준 명확히 충족)",
          evidence_doc_id: null
        });
      } 
      else {
        ambiguousItems.push({
          doc_type: "passport",
          reason: "여권 만료 기준 180일 ±90일 근접",
          extracted_value: expiryDate
        });
      }
    } else {
      // 만료일 추출 실패 → warning (사람이 확인)
      ruleResults.push({
        req_id: reqId,
        doc_type: "passport",
        status: "warning",
        decision_by: "rule",
        reason: "여권 만료일 정보를 추출할 수 없어 확인이 필요합니다.",
        evidence_doc_id: null
      });
    }
  }

  // 3-4. academic_certificate (재학증명·성적증명)
  if (docType === "academic_certificate") {
    const reqId = getReqIdByDocType("academic_certificate");
    const gpa = extracted.gpa;
    const gpaScale = extracted.gpa_scale;

    // GPA 추출 성공
    if (gpa > 0 && gpaScale > 0) {
      const gpaRatio = gpa / gpaScale;
      // 평점 2.0 이상 (4.0 만점 기준 0.5 이상) → 재정 면제 가능
      if (gpaRatio >= 0.5) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "academic_certificate",
          status: "completed",
          decision_by: "rule",
          reason: "성적증명서 제출 확인 (평점 " + gpa + "/" + gpaScale + "). 평점 2.0 이상으로 재정증명 면제 가능",
          evidence_doc_id: null
        });
      } else {
        ruleResults.push({
          req_id: reqId,
          doc_type: "academic_certificate",
          status: "warning",
          decision_by: "rule",
          reason: "성적증명서 제출 확인 (평점 " + gpa + "/" + gpaScale + "). 평점 2.0 미만으로 재정증명 면제 불가, 재정증명서 별도 제출 필요",
          evidence_doc_id: null
        });
      }
    } else {
      // GPA 추출 실패 → 그래도 서류 제출은 확인됨
      ruleResults.push({
        req_id: reqId,
        doc_type: "academic_certificate",
        status: "completed",
        decision_by: "rule",
        reason: "재학증명서·성적증명서 제출 확인",
        evidence_doc_id: null
      });
    }
  }

  // 3-5. tb_test (결핵검진)
  if (docType === "tb_test") {
    const reqId = getReqIdByDocType("tb_test");
    const issueDate = extracted.issue_date;

    // 발급일 체크 (3개월 이내 권장)
    if (issueDate) {
      const daysSinceIssue = Math.floor((new Date() - new Date(issueDate)) / (1000 * 60 * 60 * 24));
      if (daysSinceIssue > 90) {
        ruleResults.push({
          req_id: reqId,
          doc_type: "tb_test",
          status: "warning",
          decision_by: "rule",
          reason: "결핵진단서 발급일이 " + daysSinceIssue + "일 전 (3개월 초과, 재발급 권장)",
          evidence_doc_id: null
        });
      } else {
        ruleResults.push({
          req_id: reqId,
          doc_type: "tb_test",
          status: "completed",
          decision_by: "rule",
          reason: "결핵진단서 제출 확인 (발급일 " + daysSinceIssue + "일 전, 3개월 이내)",
          evidence_doc_id: null
        });
      }
    } else {
      ruleResults.push({
        req_id: reqId,
        doc_type: "tb_test",
        status: "completed",
        decision_by: "rule",
        reason: "결핵진단서 제출 확인",
        evidence_doc_id: null
      });
    }
  }

  // 3-6. application_form (통합신청서)
  if (docType === "application_form") {
    const reqId = getReqIdByDocType("application_form");
    ruleResults.push({
      req_id: reqId,
      doc_type: "application_form",
      status: "completed",
      decision_by: "rule",
      reason: "체류자격 연장 신청서 제출 확인",
      evidence_doc_id: null
    });
  }

  // 3-7. residence_proof (체류지 입증)
  if (docType === "residence_proof") {
    const reqId = getReqIdByDocType("residence_proof");
    ruleResults.push({
      req_id: reqId,
      doc_type: "residence_proof",
      status: "completed",
      decision_by: "rule",
      reason: "체류지 입증서류 제출 확인",
      evidence_doc_id: null
    });
  }

  // 3-8. family_relations (가족관계)
  if (docType === "family_relations") {
    const reqId = getReqIdByDocType("family_relations");
    ruleResults.push({
      req_id: reqId,
      doc_type: "family_relations",
      status: "completed",
      decision_by: "rule",
      reason: "가족관계 입증서류 제출 확인 (부모 명의 재정증명 시 필수)",
      evidence_doc_id: null
    });
  }

  // 3-9. 그 외 doc_type (admission_letter, business_registration, photo, professor_confirmation 등)
  const handledTypes = ["financial_statement", "passport", "academic_certificate", "tb_test", "application_form", "residence_proof", "family_relations"];
  if (!handledTypes.includes(docType)) {
    const reqId = getReqIdByDocType(docType);
    ruleResults.push({
      req_id: reqId,
      doc_type: docType,
      status: "completed",
      decision_by: "rule",
      reason: docType + " 서류 제출 확인",
      evidence_doc_id: null
    });
  }
}

// ============================================
// 4. 결과 출력
// ============================================
return [{
  json: {
    rule_results: ruleResults,
    ambiguous_items: ambiguousItems,
    needs_solar: ambiguousItems.length > 0,
    extracted_data: extracted,
    rule_count: ruleResults.length,
    solar_count: ambiguousItems.length,
    doc_type_mapping: docTypeToReqId
  }
}];

// ============================================
// 1. 현재 서류 추출 결과
// ============================================
const currentExtracted = JSON.parse($('Information Extract').item.json.choices[0].message.content);
const currentDocId = $('DB Insert: Document').item.json.doc_id;

// ============================================
// 2. 이전 서류들 가져오기 (현재 서류 제외)
// ============================================
const previousDocs = $('DB Select: PreviousDocuments').all()
  .map(item => item.json)
  .filter(doc => doc.doc_id !== currentDocId);  // 현재 서류 제외

// ============================================
// 3. 이전 서류들의 추출 정보 파싱
// ============================================
const previousExtracted = previousDocs.map(doc => {
  try {
    const fields = typeof doc.fields_json === "string" 
      ? JSON.parse(doc.fields_json) 
      : doc.fields_json;
    return {
      doc_id: doc.doc_id,
      ...fields
    };
  } catch (e) {
    return null;
  }
}).filter(x => x !== null);

// ============================================
// 4. 교차검증 결과 배열
// ============================================
const crossCheckResults = [];

// 4-1. 이름 일치 검증
if (currentExtracted.applicant_name && previousExtracted.length > 0) {
  for (const prev of previousExtracted) {
    if (prev.applicant_name && prev.applicant_name.trim() !== "") {
      const currentName = currentExtracted.applicant_name.trim().toUpperCase();
      const prevName = prev.applicant_name.trim().toUpperCase();

      if (currentName === prevName) {
        crossCheckResults.push({
          check_type: "name",
          status: "match",
          message: "이름 일치 (" + currentExtracted.applicant_name + ") - 현재 서류와 이전 " + prev.document_type + " 비교",
          related_doc_ids: [currentDocId, prev.doc_id]
        });
      } else {
        crossCheckResults.push({
          check_type: "name",
          status: "mismatch",
          message: "이름 불일치: 현재 서류(" + currentExtracted.applicant_name + ") vs 이전 " + prev.document_type + "(" + prev.applicant_name + ")",
          related_doc_ids: [currentDocId, prev.doc_id]
        });
      }
      break;  // 첫 이전 서류와 한 번만 비교 (중복 방지)
    }
  }
}

// 4-2. 대학명 일치 검증
if (currentExtracted.university_name && previousExtracted.length > 0) {
  for (const prev of previousExtracted) {
    if (prev.university_name && prev.university_name.trim() !== "") {
      const currentUni = currentExtracted.university_name.trim();
      const prevUni = prev.university_name.trim();

      if (currentUni === prevUni) {
        crossCheckResults.push({
          check_type: "university_name",
          status: "match",
          message: "대학명 일치 (" + currentUni + ") - 현재 서류와 이전 " + prev.document_type + " 비교",
          related_doc_ids: [currentDocId, prev.doc_id]
        });
      } else {
        crossCheckResults.push({
          check_type: "university_name",
          status: "mismatch",
          message: "대학명 불일치: 현재(" + currentUni + ") vs 이전 " + prev.document_type + "(" + prevUni + ")",
          related_doc_ids: [currentDocId, prev.doc_id]
        });
      }
      break;
    }
  }
}

// 4-3. 국적 ↔ 결핵검진 매칭 (이전 서류 안 봄, 현재 서류 안에서만)
if (currentExtracted.nationality) {
  const highRiskCountries = ["중국", "베트남", "네팔", "필리핀", "인도네시아", "미얀마", "캄보디아", "방글라데시", "스리랑카", "몽골", "우즈베키스탄", "러시아", "태국", "라오스", "키르기스스탄"];
  const isHighRisk = highRiskCountries.some(country => currentExtracted.nationality.includes(country));

  // 이전 서류 중 tb_test가 있는지 확인
  const hasTbTest = previousExtracted.some(prev => prev.document_type === "tb_test") 
    || currentExtracted.document_type === "tb_test";

  if (isHighRisk && !hasTbTest) {
    crossCheckResults.push({
      check_type: "nationality_tb_test",
      status: "missing",
      message: "국적(" + currentExtracted.nationality + ")이 결핵 고위험 35개국에 해당하나 결핵진단서 미제출",
      related_doc_ids: [currentDocId]
    });
  } else if (isHighRisk && hasTbTest) {
    crossCheckResults.push({
      check_type: "nationality_tb_test",
      status: "match",
      message: "국적(" + currentExtracted.nationality + ") 결핵 고위험국 출신 + 결핵진단서 제출 확인",
      related_doc_ids: [currentDocId]
    });
  }
}

// ============================================
// 5. 결과 출력
// ============================================
return [{
  json: {
    cross_check_results: crossCheckResults,
    current_doc_id: currentDocId,
    previous_doc_count: previousExtracted.length,
    check_count: crossCheckResults.length
  }
}];
